import React, { useState } from 'react';
import './Priorities.css';

const priorities = [
  {
    num: '01',
    title: 'Advocacy',
    body: `With the responsibility of the Vice President, know that I will advocate for our
students, our communities, and our Registered Student Organizations, making sure you
are supported and heard when facing your biggest hurdles as individuals who have come
here today to SJSU.`,
  },
  {
    num: '02',
    title: 'Transparency',
    body: `This position requires that I adjust and amend the agendas of the Association
Meetings as Chief Administrative Officer, as well as the Chair of the Board of
Directors. My role will allow me to provide transparency and accountability to students
in terms of the agendas and legislation being voted on, which impact all students at SJSU.`,
  },
  {
    num: '03',
    title: 'Accessibility',
    body: `I am committed to ensuring the accessibility of all resources to students, including
Registered Student Organizations. In addition, I will work to increase the access of
opportunities and research to all of our communities, prioritizing our students.`,
  },
];

export default function Priorities() {
  const [active, setActive] = useState(0);
  const [feedback, setFeedback] = useState('');
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!feedback.trim()) return;
    // In production wire this to a form backend (Formspree, EmailJS, etc.)
    // For now just log + show thanks
    console.log('Feedback submitted:', feedback);
    setSubmitted(true);
    setFeedback('');
  };

  return (
    <section id="priorities" className="priorities-section">
      <div className="inner">
        <span className="section-label reveal">What I Stand For</span>
        <h2 className="section-title reveal d1">Focus &amp; Priorities</h2>

        {/* Fixed-height scrollable box */}
        <div className="pri-container reveal d2">
          {/* Left: nav numbers */}
          <div className="pri-nav">
            {priorities.map((p, i) => (
              <button
                key={p.num}
                className={`pri-nav-btn ${active === i ? 'active' : ''}`}
                onClick={() => setActive(i)}
              >
                <span className="pri-nav-num">{p.num}</span>
                <span className="pri-nav-lbl">{p.title}</span>
              </button>
            ))}
          </div>

          {/* Right: content panel */}
          <div className="pri-panel" key={active}>
            <div className="pri-num-big">{priorities[active].num}</div>
            <h3 className="pri-title">{priorities[active].title}</h3>
            <p className="pri-body">{priorities[active].body}</p>
          </div>
        </div>

        {/* Feedback area */}
        <div className="pri-feedback reveal d3">
          <h3 className="feedback-title">Share Your Feedback</h3>
          <p className="feedback-sub">
            What issues matter most to you? Shannon wants to hear from you.
          </p>

          {submitted ? (
            <div className="feedback-thanks">
              Thank you for your input! Shannon will take this to heart. 💚
            </div>
          ) : (
            <form className="feedback-form" onSubmit={handleSubmit}>
              <textarea
                className="feedback-textarea"
                placeholder="Write your thoughts, concerns, or ideas here…"
                rows={5}
                value={feedback}
                onChange={(e) => setFeedback(e.target.value)}
              />
              <button type="submit" className="btn-primary feedback-submit">
                Send Feedback
              </button>
            </form>
          )}
        </div>
      </div>
    </section>
  );
}
